def kth_ordered(words, k):
    if k < 1 or k > len(words):
        return None

    # Group words by length
    grouped_words = {}
    for word in words:
        length = len(word)
        if length not in grouped_words:
            grouped_words[length] = []
        grouped_words[length].append(word)

    ordered_words = []
    for length in sorted(grouped_words.keys()):
        # Sort words of the same length reverse-alphabetically
        grouped_words[length].sort(reverse=True)
        ordered_words.extend(grouped_words[length])

    return ordered_words[k-1]
